import React, { useState, useEffect } from 'react';
import {
  Box,
  Typography,
  TextField,
  Button,
  Grid,
  Paper,
  Avatar,
  Switch,
  FormControlLabel,
  Divider,
  CircularProgress
} from '@mui/material';
import { useFirebase } from '../../context/FirebaseContext';
import { Company } from '../../types';

interface CompanyFormProps {
  company?: Company;
  onCancel: () => void;
  onSaved: () => void;
}

const defaultCompany: Omit<Company, 'id'> = {
  name: '',
  logo: '',
  color: '#1976D2',
  isMain: false,
  description: '',
  website: '',
  phone: '',
  email: '',
  address: ''
};

const CompanyForm: React.FC<CompanyFormProps> = ({ company, onCancel, onSaved }) => {
  const { addCompany, editCompany } = useFirebase();
  const [form, setForm] = useState<Omit<Company, 'id'>>(company || defaultCompany);
  const [loading, setLoading] = useState<boolean>(false);
  const [logoError, setLogoError] = useState<string>('');
  
  const isEditing = !!company;
  
  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type, checked } = e.target;
    setForm(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));
    
    if (name === 'logo') {
      setLogoError('');
    }
  };
  
  const validateLogoUrl = (url: string): boolean => {
    if (!url) return false;
    
    try {
      new URL(url);
      return true;
    } catch (e) {
      return false;
    }
  };
  
  const handleSave = async () => {
    // Validate logo URL
    if (!validateLogoUrl(form.logo)) {
      setLogoError('Пожалуйста, введите корректный URL логотипа');
      return;
    }
    
    try {
      setLoading(true);
      
      if (isEditing && company) {
        await editCompany(company.id, form);
      } else {
        await addCompany(form);
      }
      
      onSaved();
    } catch (error) {
      console.error('Ошибка при сохранении компании:', error);
    } finally {
      setLoading(false);
    }
  };
  
  return (
    <Paper sx={{ p: 3, borderRadius: 2, mb: 4 }}>
      <Typography variant="h5" component="h2" gutterBottom>
        {isEditing ? `Редактирование: ${company?.name}` : 'Новая компания'}
      </Typography>
      <Divider sx={{ mb: 3 }} />
      
      <Grid container spacing={3}>
        <Grid item xs={12} md={8}>
          <TextField
            fullWidth
            label="Название компании"
            name="name"
            value={form.name}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
            required
          />
        </Grid>
        <Grid item xs={12} md={4}>
          <TextField
            fullWidth
            label="Цвет бренда"
            name="color"
            value={form.color}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
            type="color"
          />
        </Grid>
        
        <Grid item xs={12}>
          <TextField
            fullWidth
            label="URL логотипа"
            name="logo"
            value={form.logo}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
            required
            error={!!logoError}
            helperText={logoError}
          />
        </Grid>
        
        {form.logo && (
          <Grid item xs={12} sx={{ display: 'flex', justifyContent: 'center', mb: 2 }}>
            <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
              <Typography variant="subtitle2" gutterBottom>
                Предпросмотр логотипа:
              </Typography>
              <Avatar
                src={form.logo}
                alt={form.name}
                variant="rounded"
                sx={{ width: 120, height: 120, border: '1px solid #eee' }}
              />
            </Box>
          </Grid>
        )}
        
        <Grid item xs={12}>
          <TextField
            fullWidth
            label="Описание"
            name="description"
            value={form.description}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
            multiline
            rows={3}
          />
        </Grid>
        
        <Grid item xs={12}>
          <Typography variant="h6" gutterBottom sx={{ mt: 2 }}>
            Контактная информация
          </Typography>
          <Divider sx={{ mb: 2 }} />
        </Grid>
        
        <Grid item xs={12} md={6}>
          <TextField
            fullWidth
            label="Веб-сайт"
            name="website"
            value={form.website}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} md={6}>
          <TextField
            fullWidth
            label="Email"
            name="email"
            value={form.email}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
            type="email"
          />
        </Grid>
        <Grid item xs={12} md={6}>
          <TextField
            fullWidth
            label="Телефон"
            name="phone"
            value={form.phone}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        <Grid item xs={12} md={6}>
          <TextField
            fullWidth
            label="Адрес"
            name="address"
            value={form.address}
            onChange={handleChange}
            variant="outlined"
            margin="normal"
          />
        </Grid>
        
        <Grid item xs={12}>
          <FormControlLabel
            control={
              <Switch
                checked={form.isMain}
                onChange={handleChange}
                name="isMain"
                color="primary"
              />
            }
            label="Установить как основную компанию"
          />
        </Grid>
        
        <Grid item xs={12}>
          <Box sx={{ display: 'flex', justifyContent: 'flex-end', mt: 3 }}>
            <Button 
              variant="outlined" 
              onClick={onCancel}
              sx={{ mr: 2 }}
              disabled={loading}
            >
              Отмена
            </Button>
            <Button 
              variant="contained"
              color="primary"
              onClick={handleSave}
              disabled={loading || !form.name || !form.logo}
              startIcon={loading ? <CircularProgress size={24} color="inherit" /> : null}
            >
              {isEditing ? 'Обновить' : 'Создать'}
            </Button>
          </Box>
        </Grid>
      </Grid>
    </Paper>
  );
};

export default CompanyForm;
